INSERT INTO `tbl_articles` (`id`, `parent_id`, `slug`, `title`, `sub_title`, `content`, `linktype`, `linksrc`, `status`, `meta_title`, `meta_keywords`, `meta_description`, `type`, `added_date`, `sortorder`, `homepage`, `image`, `fb_upload`, `date`, `category`) VALUES
(1, 0, 'about-us', 'About us', '', '<style type=\"text/css\">\r\n@media (max-width: 767px) {\r\n    h2 {\r\n        font-size: 23px;\r\n        margin-bottom: 20px;\r\n    }\r\n}\r\n.about--us.row .widget-title {\r\n    margin-bottom: 3rem;\r\n}\r\n@media (max-width: 767px) {\r\n    .about--us.row .widget-title {\r\n        margin-bottom: 5rem;\r\n    }\r\n}\r\n.about--us.row h2 {\r\n    padding: 10px 0;\r\n}\r\n@media (max-width: 767px) {\r\n    .about--us.row h2 {\r\n        padding-top: 0;\r\n    }\r\n}\r\n.about--us.row p {\r\n    margin-top: 0;\r\n    font-size: 14px;\r\n}\r\n.about--us {\r\n    margin-top: 7.5rem;\r\n}</style>\r\n<h5 style=\"line-height: 1.5\">\r\n	Welcome to the Best Luxury Jungle Resort in Chitwan &ndash; River Bank Jungle Resort</h5>\r\n<h2 style=\"line-height: 1.5\">\r\n	Eco-Friendly Luxury in the Heart of Chitwan</h2>\r\n<p>\r\n	Nestled on the peaceful banks of the Rapti River in Patihani, River Bank Jungle Resort offers private plunge-pool villas, ethical jungle safaris, and true comfort right beside Chitwan National Park. Experience modern luxury blended with nature, authentic Tharu culture, and unforgettable wildlife adventures in Nepal&rsquo;s premier jungle destination.</p>\r\n<p>\r\n	<br />\r\n	Step into an elegant riverside retreat where sophisticated design meets the wild beauty of Chitwan. Stroll through spacious hallways to your private villa, unwind by the outdoor swimming pool, or relax on the vintage deck with panoramic views of the breezy Rapti River and vast Terai grasslands. As one of the top eco-friendly resorts in Chitwan, we promise pure bliss and sustainable stays that connect you deeply with nature.</p>\r\n<div class=\"row about--us\">\r\n	<div class=\"col-xs-12 col-lg-4\">\r\n		<div class=\"row\">\r\n			<div class=\"col-sm-6 col-lg-12\">\r\n				<div class=\"widget-title\">\r\n					<h5>\r\n						WHO WE ARE</h5>\r\n					<h2>\r\n						Our Mission</h2>\r\n					<p>\r\n						Dedicated to providing guests with luxurious and unforgettable experiences by offering exceptional hospitality, world-class amenities, and unparalleled natural beauty momentarily encouraging sustainability and responsible tourism</p>\r\n				</div>\r\n			</div>\r\n			<div class=\"col-sm-6 col-lg-12\">\r\n				<div class=\"widget-title\">\r\n					<h5>\r\n						WHAT WE DO</h5>\r\n					<h2>\r\n						Our Vision</h2>\r\n					<p>\r\n						We are devoted to crafting unforgettable experiences, and enveloping luxury while championing sustainability and responsible tourism.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"col-lg-8 \">\r\n		<img src=\"/assets/userfiles/images/aboutus.png\" width=\"100%\" /></div>\r\n</div>\r\n', 0, '', 1, 'About - Jungle Resort in Chitwan', 'Chitwan luxury resort, River Bank Jungle Resort about us, eco-friendly Chitwan hotel, Rapti River luxury stay, vintage deck views, forest edge resort, Resort in Chitwan, Bharatpur Resort, Resort near Chitwan', 'Discover River Bank Jungle Resort, the best luxury jungle resort in Chitwan. Enjoy private plunge-pool villas, safaris & eco-friendly stays near Chitwan.', 0, '2017-04-23 18:29:11', 4, 0, 0x613a313a7b693a303b733a32323a22434373756b2d72384136522d61626f75742e77656270223b7d, 0x46566936662d72384136522d61626f75742e6a7067, '', ''),
(12, 0, 'recreation', 'Recreation', '', '<style type=\"text/css\">\r\n.riverbank_acitivties h4{\r\n  line-height: 1.5\r\n}\r\n@media (max-width:1000px){\r\n	.widget-article-carousel{\r\n	display:none;\r\n	}\r\n	.row.row_flex .col-xs-12:not(:last-child){\r\n	 margin-bottom: 10px !important;\r\n	}\r\n	.row.row_flex .col-xs-12{\r\n	padding-inline: 0;\r\n	}\r\n	.widget-inner .row .col-md-12 .row {\r\n		margin-bottom: 3rem !important;\r\n	}\r\n	}\r\n	@media (min-width:1000px){\r\n	.display_on_device{\r\n	display:none;\r\n	}\r\n	.row.row_flex{\r\n	flex-direction: row;\r\n	}\r\n	}\r\n	.widget-inner .row{\r\n			 display: flex;\r\n			justify-content: center;\r\n			align-items: center;\r\n		}\r\n		@media (max-width:922px){\r\n			.widget-inner .row{\r\n			flex-direction: column;\r\n			}\r\n			.event-page-inner .row:nth-child(even){\r\n		flex-direction: column-reverse;\r\n		}\r\n		.widget-inner h2{\r\n			margin: 2rem 0;\r\n		}\r\n		}\r\n		.widget-inner .riverbank_acitivties{\r\n		  padding-inline: 5rem;\r\n		}\r\n		.widget-inner .row .col-md-12 .row{\r\n		  margin-bottom: 8rem;\r\n		}\r\n	@media (max-width:767px){\r\n		.widget-inner .riverbank_acitivties {\r\n		padding-inline: 0;\r\n	}\r\n	}</style>\r\n<h2 style=\"text-align: center;\">\r\n	<span style=\"color:#008080;\">IN RIVER BANK JUNGLE RESORT<br />\r\n	<br />\r\n	ENJOYMENT, LEISURE, RELAXATION</span></h2>\r\n<p>\r\n	&nbsp;</p>\r\n<div class=\"event-page-inner\">\r\n	<div class=\"row\">\r\n		<div class=\"col-lg-6 col-md-6\">\r\n			<div class=\"widget-article-carousel\">\r\n				<div class=\"widget-carousel owl-carousel owl-theme\">\r\n					<div class=\"testimonials-item\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/pool.jpg\" style=\"width: 100%;\" /></div>\r\n					<div class=\"testimonials-item\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/pool1.jpg\" style=\"width: 100%;\" /></div>\r\n					<div class=\"testimonials-item\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/pool2.jpg\" style=\"width: 100%;\" /></div>\r\n					<div class=\"testimonials-item\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/pool3.jpg\" style=\"width: 100%;\" /></div>\r\n					<div class=\"testimonials-item\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/pool4.jpg\" style=\"width: 100%;\" /></div>\r\n					<div class=\"testimonials-item\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/pool5.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n			<div class=\"display_on_device\">\r\n				<div class=\"row row_flex\">\r\n					<div class=\"col-md-6 col-xs-12\">\r\n						<img alt=\"\" src=\"/assets/userfiles/images/pool5.jpg\" width=\"100%\" /></div>\r\n					<div class=\"col-md-6 col-xs-12\">\r\n						<img alt=\"\" src=\"/assets/userfiles/images/pool.jpg\" width=\"100%\" /></div>\r\n					<div class=\"col-md-6 col-xs-12\">\r\n						<img alt=\"\" src=\"/assets/userfiles/images/pool1.jpg\" width=\"100%\" /></div>\r\n					<div class=\"col-md-6 col-xs-12\">\r\n						<img alt=\"\" src=\"/assets/userfiles/images/pool5.jpg\" width=\"100%\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-6 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						SWIMMING POOL</h2>\r\n					<h4>\r\n						&quot;Experience the allure of our exquisite swimming pool&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Unwind the negativity at the heart of Chitwan National Park, with your favorite sip of refreshing beverages. Calming the mind, relaxing the body and enriching the soul with the grandeur panoramic Chitwan National Park vistas.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						YOGA</h2>\r\n					<h4>\r\n						&quot;Breathe in the wild, enrich your soul&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						River Bank believe in holistic approach of wellness. Set on the awestruck back drop of Rapti River and vast Chitwan National Park, you find your inner balance and mental peace through Yoga. Breathe in the wild, enrich your soul.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/yoga(1).jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n', 0, '', 1, 'Recreation', 'river bank jungle resort, recreation Chitwan, swimming pool Chitwan resort, yoga Chitwan National Park, leisure activities Chitwan, relaxation Rapti River, jungle resort Nepal recreation, resort in chitwan, riverside resort', 'Relax and recharge at River Bank Jungle Resort in Chitwan, Nepal. Dive into our luxurious swimming pool with Chitwan National Park views.', 0, '2024-06-14 15:13:55', 2, 0, 0x613a313a7b693a303b733a32373a2264584756702d72656c73562d706f6f6c62616e6e65722e77656270223b7d, 0x56344b43652d706f6f6c312e6a7067, '', ''),
(13, 0, 'riverbank-jungle-resort', 'Riverbank Jungle Resort', '', '<div class=\"widget-about-promo hoempage_about_promo\">\r\n	<div class=\"widget-inner\">\r\n		<div class=\"row\">\r\n			<div class=\"col-md-12 home_page_about\">\r\n				<h1 class=\"heading-resort-title\">\r\n					Welcome to the Best Luxury Jungle Resort in Chitwan &ndash; River Bank Jungle Resort</h1>\r\n				<h3 class=\"custom-align\">\r\n					Eco-Friendly Luxury in the Heart of Chitwan</h3>\r\n				<p>\r\n					Nestled on the peaceful banks of the Rapti River in Patihani, River Bank Jungle Resort offers private plunge-pool villas, ethical jungle safaris, and true comfort right beside Chitwan National Park. Experience modern luxury blended with nature, authentic Tharu culture, and unforgettable wildlife adventures in Nepal&rsquo;s premier jungle destination.</p>\r\n				<p>\r\n					<a class=\"btn\" href=\"/../about-us\">READ MORE</a></p>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n<div class=\"row md_top_margin\">\r\n	<div class=\"col-md-12 home_about_padding\">\r\n		<img alt=\"about home\" class=\"center-img\" height=\"510\" loading=\"lazy\" src=\"/../userfiles/images/facilities-banner.webp\" width=\"1140\" /></div>\r\n</div>\r\n<style type=\"text/css\">\r\n.custom-align {\r\ntext-align: center;\r\n}</style>\r\n', 0, 'about-us', 1, 'River Bank Jungle Resort – Best Luxury Resort in Chitwan', 'Resort in Chitwan, Best Resort in Chitwan, Riverbank Jungle Resort, River View, Luxury Accommodation, Best Price Resort in Chitwan, Jungle Resort, Riverside Villas, Modern Amenities, Patihani Resort, Bharatpur Resort', 'Experience best luxury jungle resort in Chitwan at River Bank Jungle Resort, Patihani. Riverside villas with Tharu culture and stunning Rapti River views.', 0, '2024-07-02 18:15:37', 5, 1, 0x613a303a7b7d, '', '', ''),
(8, 0, 'sustainability', 'Sustainability', '', '<style type=\"text/css\">\r\n@media (max-width:922px){\r\n		.sustainability_text_wrapper .go_green {\r\n		color: #fff;\r\n		background-repeat: no-repeat;\r\n		background-color: #2d452d;\r\n		background-image: none;\r\n	}\r\n	.sustainability_text_wrapper .row {\r\n		flex-direction: column;\r\n	}\r\n	\r\n	.go_green .col-md-4 img {\r\n			display: block;\r\n			margin-inline: auto;\r\n		}\r\n		.sustainability .first_row_child {\r\n		background:none;\r\n	}\r\n	.sustainability .first_row_child img {\r\n		filter: none;\r\n	}\r\n	.wrapper, .wrapper-inner {\r\n	 padding: 0;\r\n		}\r\n	}\r\n	@media (max-width:767px){\r\n		.sustainability_text_wrapper .row {\r\n			flex-direction: column;\r\n			padding: 10px;\r\n		}\r\n		.sustainability_text_wrapper .go_green .eco_bg {\r\n		padding: 0rem;\r\n	}\r\n	.go_green_stakeholders .row  .col-sm-2 img{\r\n	margin-bottom: 20px;\r\n	}\r\n	.sustainability .first_row_child img {\r\n			filter: none;\r\n			width: 50%;\r\n			display: block;\r\n			margin-inline: auto;\r\n		}\r\n		.widget-inner h2 {\r\n			margin: 3rem 0;\r\n			font-size: 2rem;\r\n			line-height: 1.6;\r\n		}\r\n	}</style>\r\n<div class=\"container\">\r\n	<div class=\"sustainability\">\r\n		<div class=\"row sustainability_flex\">\r\n			<div class=\"col-md-10\">\r\n				<div class=\"sustainability_text\">\r\n					<h2 class=\"text-uppercase\">\r\n						Commitment To <b> Greener Tomorrow</b></h2>\r\n					<p>\r\n						At River Bank, our commitment to environmental responsibility shines through our organic farming, ensuring a supply of fresh, chef-crafted meals. Explore our gardens, where herbs naturally protect our crops, and seasonal rotations enrich our cuisine. Our dedication extends to efficient waste management and rainwater harvesting, showcasing our commitment to sustainable practices</p>\r\n				</div>\r\n			</div>\r\n			<div class=\"col-md-12\" style=\"padding:0\">\r\n				<img alt=\"\" src=\"/assets/userfiles/images/eco%20system.png\" width=\"100%\" /></div>\r\n		</div>\r\n		<div class=\"sustainability_text_wrapper\">\r\n			<div class=\"row first_row_child\">\r\n				<div class=\"col-md-6\">\r\n					<div class=\"row\">\r\n						<div class=\"col-sm-3\">\r\n							<img alt=\"plant\" src=\"/assets/userfiles/images/9.png\" width=\"100%\" /></div>\r\n						<div class=\"col-sm-9 sustainability-bg-white\">\r\n							<p>\r\n								It is not something we do, it is who we are. Believing in Mother Nature and practitioner on the same, we are contributing to the better place to live for everyone.</p>\r\n						</div>\r\n					</div>\r\n				</div>\r\n				<div class=\"col-md-6\">\r\n					<div class=\"row\">\r\n						<div class=\"col-sm-3\">\r\n							<img alt=\"plant\" src=\"/assets/userfiles/images/8.png\" width=\"100%\" /></div>\r\n						<div class=\"col-sm-9 sustainability-bg-white\">\r\n							<p>\r\n								River bank practice waste reduction, recycling effort ans zero waste initiatives. We supremely trust the process of composting and the use or reuse or biodegradable amenities.</p>\r\n						</div>\r\n					</div>\r\n				</div>\r\n			</div>\r\n			<!-- image with text -->\r\n			<div class=\"row go_green\">\r\n				<div class=\"col-md-4\">\r\n					<img alt=\"\" src=\"/assets/userfiles/images/riverbak.png\" /></div>\r\n				<div class=\"col-md-8  eco_bg\">\r\n					<div class=\"row go_green_stakeholders\">\r\n						<div class=\"col-sm-12\">\r\n							<div class=\"row\">\r\n								<div class=\"col-sm-2\">\r\n									<img alt=\"\" src=\"/assets/userfiles/images/earh.png\" width=\"100px\" /></div>\r\n								<div class=\"col-sm-10\">\r\n									<p>\r\n										We stakeholders, being a naturalist, are the practitioner of trans-formative journey towards responsibility future. Believing in sustainable ecosystem, we make an efforts towards wildlife conservation, such as preserving natural habitat through collaboration with local conservation organizations.</p>\r\n								</div>\r\n							</div>\r\n						</div>\r\n					</div>\r\n					<!-- 2nd -->\r\n					<div class=\"row  go_green_stakeholders\">\r\n						<div class=\"col-sm-12\">\r\n							<div class=\"row\">\r\n								<div class=\"col-sm-2\">\r\n									<img alt=\"\" src=\"/assets/userfiles/images/Vector-1.png\" width=\"77px\" /></div>\r\n								<div class=\"col-sm-10\">\r\n									<p>\r\n										Our sustainability journey is anchored by four essential pillars: Environmental Responsibility, Corporate Social Responsibility, Organic Farm, and Rain Water Harvest. We stakeholders, being a naturalist, are the practitioner of trans-formative journey towards responsibility future.</p>\r\n								</div>\r\n							</div>\r\n						</div>\r\n					</div>\r\n					<!-- 2nd end --></div>\r\n			</div>\r\n			<!-- image with text end --></div>\r\n	</div>\r\n</div>\r\n', 0, '', 1, 'Sustainability', 'river bank jungle resort, sustainability Chitwan, eco-friendly resort Nepal, sustainable tourism Chitwan, organic farming Chitwan, rainwater harvesting resort, wildlife conservation Nepal, Chitwan National Park, Chitwan jungle resort sustainability', 'River Bank Jungle Resort in Chitwan champions sustainability through organic farming, rainwater harvesting, waste reduction, and wildlife conservation', 0, '2024-06-11 14:49:35', 1, 0, 0x613a313a7b693a303b733a32333a2239473635692d58443750652d67617264656e2e77656270223b7d, 0x7752724a332d58443750652d67617264656e2e6a7067, '', ''),
(11, 0, 'experience', 'Experience', '', '<style type=\"text/css\">\r\n.widget-inner .row{\r\n			 display: flex;\r\n			justify-content: center;\r\n			align-items: center;\r\n		}\r\n	.event-page-inner .row{\r\n		scroll-margin-top: 14rem;\r\n	  }\r\n		@media (max-width:922px){\r\n			.widget-inner .row{\r\n			flex-direction: column;\r\n			}\r\n			.event-page-inner .row:nth-child(even){\r\n		flex-direction: column-reverse;\r\n		}\r\n		.widget-inner h2{\r\n			margin: 2rem 0;\r\n		}\r\n		}\r\n		.widget-inner .riverbank_acitivties{\r\n		  padding-inline: 5rem;\r\n		}\r\n		.widget-inner .row .col-md-12 .row{\r\n		  margin-bottom: 8rem;\r\n		}\r\n		\r\n		@media (max-width:767px){\r\n			.widget-inner .riverbank_acitivties {\r\n			padding-inline: 0;\r\n		}</style>\r\n<h2 style=\"text-align: center; margin-bottom:50px;\">\r\n	<span style=\"color:#008080;\">RIVER BANK JUNGLE ACTIVITIES<br />\r\n	<br />\r\n	THEIR LAND; YOUR ADVENTURE</span></h2>\r\n<div class=\"event-page-inner\">\r\n	<div class=\"row\" id=\"sundowner\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"River bank Experience\" src=\"/assets/userfiles/images/sundowner.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						SUNDOWNER</h2>\r\n					<h4>\r\n						&quot;Golden Hours, Endless Memories&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						As the sun dips below the horizon, our 5-star resort invites you to savor the magic of a sundowner. Picture this: a secluded terrace, soft jazz notes in the air, and your favorite libation in hand. The sky blushes with hues of apricot and lavender, casting a golden glow on the landscape. Whether you choose a classic martini or a tropical elixir, each sip is a celebration of the day&rsquo;s journey.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"canoe_safari\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						CANOEING SAFARI</h2>\r\n					<h4>\r\n						&quot;Paddle into Paradise: Canoeing Adventures Await&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Commence on a captivating canoeing safari through our pristine waters. Glide silently, surrounded by lush greenery and wildlife. Our expert oarsmen guide you, ensuring a serene and unforgettable experience. Let the rhythmic strokes of your paddle lead you to hidden corners of beauty. Witness sun-kissed reflections, listen to the symphony of birds, and feel the gentle current beneath you. At our 5-star resort, every canoeing adventure is a voyage into serenity.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/canoeing.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"bird_gazing\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/bird.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						BIRD GAZING</h2>\r\n					<h4>\r\n						&quot;Chirps and Whispers: Our Aerial Haven&quot;</h4>\r\n					<div>\r\n						<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n							Welcome to our lush sanctuary in Chitwan, where nature&rsquo;s feathered wonders take center stage. As dawn breaks, witness the rare Bengal florican gracefully dance across the grasslands. Marvel at the vibrant paradise flycatcher, its plumage a living canvas of colors. And listen to the symphony of sunbirds, kingfishers, and jungle fowl &ndash; a chorus that echoes through our pristine habitat. Whether you&rsquo;re an avid birder or simply seeking serenity, our resort invites you to explore the skies and discover the magic of flight.</p>\r\n					</div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"crocodile_breeding\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						CROCODILE BREEDING</h2>\r\n					<h4>\r\n						&quot;Jaws of Chitwan: Where Ancient Reptiles Thrive&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Step into our conservation haven, where the elusive Gharial crocodile finds sanctuary. These endangered creatures, with their distinctive snouts, thrive within our protected park. Our dedicated farm, established in 1978, is a lifeline for their survival. Here, we rescue and nurture wild eggs, releasing the young Gharials back into the river&rsquo;s embrace. And for those seeking an up-close encounter, behold the formidable mugger crocodiles &ndash; ancient sentinels of the waterways. Join us in safeguarding these majestic reptiles and witness their legacy unfold.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/breeding.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"jeep__safari\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/jeep.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						JEEP SAFARI</h2>\r\n					<h4>\r\n						&quot;Off-Road Thrills, Nature Unveiled&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Welcome to our natural sanctuary, where the pulse of the jungle beats in harmony with life. Here, the legendary one-horned rhino roams freely, its ancient armor a testament to resilience. The elusive Bengal tiger prowls through sun-dappled foliage, while elephants trumpet their majestic presence. Glide along the river banks, where gharials bask in the morning sun, and foxes dart through the underbrush. And when dawn paints the sky, embark on a sunrise jungle expedition &ndash; a symphony of sights and sounds.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"village__tour\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						VILLAGE TOUR</h2>\r\n					<h4>\r\n						&quot;Footprints in Time: Explore Our Village Treasures&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Step into the heart of tradition at our enchanting Tharu village, nestled near Pathihani. Here, the Tharus &ndash; guardians of ancient wisdom &ndash; welcome you with open arms. Accompanied by seasoned naturalists and local guides, immerse yourself in their captivating world. Witness their vibrant dances, hear tales passed down through generations, and taste flavors that echo centuries. Despite their forest-bound heritage, the Tharu community has adapted, embracing agriculture, fishing, and cattle rearing.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/village.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"jungle__walk\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/jungle.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						JUNGLE WALK</h2>\r\n					<h4>\r\n						&quot;Wild Footprints: Explore Chitwan&rsquo;s Untamed Beauty&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Step into the heart of the wild with our captivating walking safaris. Whether you follow the nature trails in the buffer zone or take a leisurely stroll, prepare for enchanting encounters. Marvel at delicate butterflies, watch diligent dung beetles at work, and immerse yourself in a tapestry of wildflowers. Guided by seasoned naturalists and expert trackers, these safaris lead you through dense jungles, grassy expanses, and serene waterways. Keep your eyes peeled &ndash; from elusive wildlife to vibrant avian species, every step reveals a new chapter in Chitwan&rsquo;s untamed story.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n	<div class=\"row\" id=\"tharu_culture\">\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"riverbank_acitivties\">\r\n					<h2>\r\n						THARU CULTURAL DANCE</h2>\r\n					<h4>\r\n						&quot;Tharu Nights: Celebrate Heritage through Dance&quot;</h4>\r\n					<p style=\"box-sizing: border-box; margin: 0px 0px 10px; color: rgb(97, 97, 97); font-size: 16px;\">\r\n						Step into the beating heart of Tharu heritage &ndash; a dance that echoes centuries. Adorned in resplendent hues, the tribe sways to ancient rhythms, their movements a canvas of stories and emotions. Feel the pulse of tradition as they invite you to join &ndash; a celebration where boundaries dissolve, and you become part of their vibrant tapestry. Let the music guide your steps, and immerse yourself in the raw beauty of Tharu culture.</p>\r\n				</div>\r\n			</div>\r\n		</div>\r\n		<div class=\"col-lg-12 col-md-6\">\r\n			<div class=\"events\">\r\n				<div class=\"item\">\r\n					<div class=\"riverbank_img\">\r\n						<img alt=\"Riverbank Experience\" src=\"/assets/userfiles/images/tharudance.jpg\" style=\"width: 100%;\" /></div>\r\n				</div>\r\n			</div>\r\n		</div>\r\n	</div>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n', 0, '', 1, 'Jungle Activities & Safaris', 'Chitwan jungle activities, Chitwan safari, jeep safari Chitwan, Rapti River canoeing, Tharu cultural dance, River Bank Jungle Resort activities, jungle walk Chitwan, Chitwan resort, wildlife experiences Chitwan', 'Explore thrilling jungle activities in Chitwan: ethical jeep safaris, bird watching,cultural dance, village tours, jungle walks & crocodile breeding center.', 0, '2024-06-13 15:04:28', 3, 0, 0x613a313a7b693a303b733a32373a2230534866702d594b3671472d657870657269656e63652e77656270223b7d, 0x6f4e796e682d746861727564616e63652e6a7067, '', '');
