(1, 'River Bank Jungle Resort', '124wS-icons.webp', 'orxHf-riverbankjungleresort.png', 'River Bank Jungle Resort', 1, 'https://www.google.com/maps/embed?pb=!1m14!1m8!1m3!1d7073.745206308308!2d84.352049!3d27.566464!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x3994f70331bf8635%3A0xffbe72e6d5659a70!2sRiverbank%20Jungle%20Resort%20%7C%7C%20Wyndham%20Garden%20Chitwan!5e0!3m2!1sen!2snp!4v1718095581020!5m2!1sen!2snp', 'aHQyy-map.jpg', 'Bharatpur 22, Patihani, Chitwan, Nepal', '', '+977 5 6411121,+977 056411120', '0', '', '', 'info@riverbankjungleresort.com.np', '<h4>\r\n	<span style=\"color:#00843b;\"><strong>Riverbank Jungle Resort Pvt. Ltd.</strong></span></h4>\r\n<p>\r\n	<strong>Address</strong>: Bharatpur 22, Pathihani, Chitwan, Nepal</p>\r\n<p>\r\n	<strong>Tel</strong>: <a href=\"tel:+97756411121\">+977 5 6411121</a></p>\r\n<p>\r\n	<strong>Mob</strong>: <a href=\"tel:+977 9761734722\"> ‪+977 9761734722 </a></p>\r\n<p>\r\n	<strong>E-mail</strong>: <a href=\"mailto:info@riverbankjungleresort.com.np\">info@riverbankjungleresort.com.np</a></p>\r\n<ul class=\"contact-social\">\r\n	<li>\r\n		<a href=\"https://www.facebook.com/people/River-Bank-Jungle-Resort/61555768349361/\" target=\"_blank\"><i class=\"fa fa-facebook-square\"></i></a></li>\r\n	<li>\r\n		<a href=\"https://www.instagram.com/river_bank_jungle_resort/\" target=\"_blank\"><i class=\"fa fa-instagram\"></i></a></li>\r\n	<li>\r\n		<a href=\"https://www.tripadvisor.com/Hotel_Review-g2407100-d27121850-Reviews-River_Bank_Jungle_Resort-Bharatpur_Chitwan_District_Narayani_Zone_Central_Region.html\" target=\"_blank\"><i class=\"fa fa-tripadvisor\"></i></a></li>\r\n</ul>\r\n<hr />\r\n<p>\r\n	&nbsp;</p>\r\n<h4>\r\n	<strong style=\"color:#00843b;\">City Office</strong></h4>\r\n<p>\r\n	<strong>Address</strong>: Maharajgunj, Kathmandu, Nepal</p>\r\n<p>\r\n	<strong>Tel</strong>: <a href=\"tel:+977 1 5916478\">+977 1 5916478</a></p>\r\n<p>\r\n	<strong>Mob</strong>: <a href=\"tel:+977 9761734722\"> ‪+977 9761734722</a></p>\r\n<p>\r\n	<strong>E-mail</strong>: <a href=\"mailto:sales@riverbankjungleresort.com.np\">sales@riverbankjungleresort.com.np</a></p>\r\n', '© Copyright {year}. River Bank Jungle Resort. All Rights Reserved .', 'River Bank Jungle Resort | Luxury Jungle Resort Chitwan', 'Resort in Nepal, Resort in Chitwan, Best resort in Chitwan, Chitwan Resort, Chitwan, Chitwan Hospitality, Riverbank, River Bank Jungle Resort, Jungle Resort, Riverbank Jungle Resort Chitwan, Best Hotel in Patihani, 5 Star Reort Nepal', 'Discover River Bank Jungle Resort at Chitwan National Park. Nestled on the Rapti River\'s edge, our sophisticated design blends seamlessly with nature for a serene, enriching escape.', '<!-- Google tag (gtag.js) -->\r\n<script async src=\"https://www.googletagmanager.com/gtag/js?id=G-6H74VP4276\"></script>\r\n<script>\r\n  window.dataLayer = window.dataLayer || [];\r\n  function gtag(){dataLayer.push(arguments);}\r\n  gtag(\'js\', new Date());\r\n\r\n  gtag(\'config\', \'G-6H74VP4276\');\r\n</script>\r\n\r\n<!-- Google Tag Manager -->\r\n<script>(function(w,d,s,l,i){w[l]=w[l]||[];w[l].push({\'gtm.start\':\r\nnew Date().getTime(),event:\'gtm.js\'});var f=d.getElementsByTagName(s)[0],\r\nj=d.createElement(s),dl=l!=\'dataLayer\'?\'&l=\'+l:\'\';j.async=true;j.src=\r\n\'https://www.googletagmanager.com/gtm.js?id=\'+i+dl;f.parentNode.insertBefore(j,f);\r\n})(window,document,\'script\',\'dataLayer\',\'GTM-THJK6772\');</script>\r\n<!-- End Google Tag Manager -->\r\n\r\n<script type=\"text/javascript\">\r\n    (function(c,l,a,r,i,t,y){\r\n        c[a]=c[a]||function(){(c[a].q=c[a].q||[]).push(arguments)};\r\n        t=l.createElement(r);t.async=1;t.src=\"https://www.clarity.ms/tag/\"+i;\r\n        y=l.getElementsByTagName(r)[0];y.parentNode.insertBefore(t,y);\r\n    })(window, document, \"clarity\", \"script\", \"wnrp1bzqwv\");\r\n</script>', 2, 'result.php', '5gU2lD7', 'web', 'blue', '', '', 'Develop By Amit prajapati', 'Develop By Amit prajapati', 0, 'Maharajgunj, Kathmandu, Nepal', '+977 9761734722', '+977 1 5916478', 'sales@riverbankjungleresort.com.np', '+9779761734722,+9779802390019', '', 'zIRUt-1.jpg', 'QrPvQ-1.jpg');
