(10, '2-sup-nd-sup-anniversary-special-offer-i', '2<sup>nd </sup>Anniversary Special Offer I', 'st8ek-1.jpg', '3xiIP-1 Night _ 2 Days Package.jpg', '', 9, 0, '', 0, 160, 0, '', '<div class=\"row\">\r\n	<div class=\"col-md-6\">\r\n		<img alt=\"Offer\" src=\"/assets/userfiles/images/offer1(1).jpg\" width=\"100%\" /></div>\r\n	<div class=\"col-md-6\">\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>PACKAGE INCLUSIONS</strong></p>\r\n		<p>\r\n			<strong>Day 1</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Welcome drink on arrival</li>\r\n			<li>\r\n				Briefing about the program</li>\r\n			<li>\r\n				Check-in at <strong>River Bank Jungle Resort</strong></li>\r\n			<li>\r\n				Buffet lunch</li>\r\n			<li>\r\n				Tharu/Darai Village Tour</li>\r\n			<li>\r\n				Poolside sunset view with tea/coffee and light snacks</li>\r\n			<li>\r\n				Slide presentation on Chitwan&#39;s Natural Beauties (venue based on group size)</li>\r\n			<li>\r\n				Buffet dinner</li>\r\n		</ul>\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>Day 2</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Wake-up call with tea/coffee</li>\r\n			<li>\r\n				<strong>Morning Jeep Safari</strong> inside Chitwan National Park</li>\r\n			<li>\r\n				Buffet breakfast</li>\r\n			<li>\r\n				Departure</li>\r\n		</ul>\r\n	</div>\r\n</div>\r\n<style type=\"text/css\">\r\n.bullet-default li{\r\nlist-style:circle; \r\nlist-style-position: inside;\r\n}</style>\r\n', 1, 1, 1, '2025-12-30', '2025-11-02', '2025-11-02 12:50:20', 8, 1, '', '', ''),
(11, '2-sup-nd-sup-anniversary-special-offer-ii', '2<sup>nd</sup> Anniversary Special Offer II', 'DNGkU-2.jpg', 'CcafG-2 Nights _ 3 Days Package.jpg', '', 9, 0, '', 0, 250, 0, '', '<div class=\"row\">\r\n	<div class=\"col-md-6\">\r\n		<img alt=\"Offer\" src=\"/assets/userfiles/images/offer2(1).jpg\" style=\"width: 100%;\" /></div>\r\n	<div class=\"col-md-6\">\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>PACKAGE INCLUSIONS</strong></p>\r\n		<p>\r\n			<strong>2 Nights / 3 Days Package</strong></p>\r\n		<p>\r\n			<strong>Day 1</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Welcome drink on arrival</li>\r\n			<li>\r\n				Program briefing &amp; check-in</li>\r\n			<li>\r\n				Buffet lunch</li>\r\n			<li>\r\n				Tharu/Darai Village Tour</li>\r\n			<li>\r\n				Poolside sunset view with tea/coffee and light snacks</li>\r\n			<li>\r\n				Slide presentation on Chitwan&#39;s Natural Beauties</li>\r\n			<li>\r\n				Buffet dinner</li>\r\n		</ul>\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>Day 2</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Wake-up call</li>\r\n			<li>\r\n				Morning tea/coffee at Coffee Shop</li>\r\n			<li>\r\n				Jungle walk</li>\r\n			<li>\r\n				Buffet breakfast</li>\r\n			<li>\r\n				<strong>Canoeing on the Rapti River</strong> followed by a visit to the <strong>Crocodile Breeding Centre</strong> inside the National Park</li>\r\n			<li>\r\n				Buffet lunch</li>\r\n			<li>\r\n				<strong>Jeep Safari</strong> inside the National Park (SIC basis)</li>\r\n			<li>\r\n				Poolside tea/coffee</li>\r\n			<li>\r\n				<strong>Indigenous Cultural Dance (Tharu/Darai Show)</strong></li>\r\n			<li>\r\n				<strong>BBQ Dinner</strong> in open space facing the Rapti River</li>\r\n		</ul>\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>Day 3</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Wake-up call</li>\r\n			<li>\r\n				Morning tea/coffee at Coffee Shop</li>\r\n			<li>\r\n				<strong>Bird Watching</strong></li>\r\n			<li>\r\n				Buffet breakfast</li>\r\n			<li>\r\n				Check-out</li>\r\n		</ul>\r\n	</div>\r\n</div>\r\n<style type=\"text/css\">\r\n.bullet-default li{\r\nlist-style:circle; \r\nlist-style-position: inside;\r\n}</style>\r\n', 1, 0, 1, '2025-12-30', '2025-11-02', '2025-11-02 13:16:26', 7, 1, '', '', ''),
(12, '2-sup-nd-sup-anniversary-special-offer-iii', '2<sup>nd</sup> Anniversary Special Offer III', 'y3Av3-3.jpg', '5aNQ7-3 Nights _ 4 Days Package.jpg', '', 9, 0, '', 0, 350, 0, '', '<div class=\"row\">\r\n	<div class=\"col-md-6\">\r\n		<img alt=\"Offer\" src=\"/assets/userfiles/images/offer3.jpg\" width=\"100%\" /></div>\r\n	<div class=\"col-md-6\">\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>PACKAGE INCLUSIONS</strong></p>\r\n		<p>\r\n			<strong>3 Nights / 4 Days Package</strong></p>\r\n		<p>\r\n			<strong>Day 1</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Welcome drink on arrival</li>\r\n			<li>\r\n				Program briefing &amp; check-in</li>\r\n			<li>\r\n				Buffet lunch</li>\r\n			<li>\r\n				Tharu/Darai Village Tour</li>\r\n			<li>\r\n				Poolside sunset view with tea/coffee and light snacks</li>\r\n			<li>\r\n				Slide presentation on Chitwan&#39;s Natural Beauties</li>\r\n			<li>\r\n				Buffet dinner</li>\r\n		</ul>\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>Day 2</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Wake-up call</li>\r\n			<li>\r\n				Morning tea/coffee</li>\r\n			<li>\r\n				Jungle walk</li>\r\n			<li>\r\n				Buffet breakfast</li>\r\n			<li>\r\n				Canoeing</li>\r\n			<li>\r\n				Buffet lunch</li>\r\n			<li>\r\n				Jeep Safari</li>\r\n			<li>\r\n				Poolside tea/coffee</li>\r\n			<li>\r\n				Indigenous Cultural Dance (Tharu/Darai Show)</li>\r\n			<li>\r\n				Buffet dinner</li>\r\n		</ul>\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>Day 3</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Wake-up call</li>\r\n			<li>\r\n				Breakfast</li>\r\n			<li>\r\n				Birdwatching around the riverside</li>\r\n			<li>\r\n				Lunch</li>\r\n			<li>\r\n				<strong>Jeep Safari or Cycling Tour to Local Tharu Village</strong></li>\r\n			<li>\r\n				<strong>BBQ Dinner</strong> &ndash; Open space facing the Rapti River</li>\r\n		</ul>\r\n		<p>\r\n			&nbsp;</p>\r\n		<p>\r\n			<strong>Day 4</strong></p>\r\n		<ul class=\"bullet-default\">\r\n			<li>\r\n				Wake-up call</li>\r\n			<li>\r\n				Morning tea/coffee</li>\r\n			<li>\r\n				Buffet breakfast</li>\r\n			<li>\r\n				Check-out from <strong>River Bank Jungle Resort</strong></li>\r\n		</ul>\r\n	</div>\r\n</div>\r\n<style type=\"text/css\">\r\n.bullet-default li{\r\nlist-style:circle; \r\nlist-style-position: inside;\r\n}</style>\r\n', 1, 0, 1, '2025-12-30', '2025-11-02', '2025-11-02 13:18:13', 6, 1, '', '', ''),
