INSERT INTO `tbl_package` (`id`, `slug`, `title`, `sub_title`, `image`, `fb_upload`, `header_image`, `banner_image`, `detail`, `content`, `meta_title`, `meta_keywords`, `meta_description`, `status`, `sortorder`, `added_date`, `type`) VALUES
(1, 'rooms-suites', 'Rooms & Suites', 'Quintessential 5-Star Paradise', 'a:1:{i:0;s:15:\"MvMUz-room.webp\";}', 0x715141595a2d6a417553732d64656c75786562616e6e65722e6a7067, '', 'a:1:{i:0;s:27:\"0wEnB-T6fdV-roombanner.webp\";}', '', '<p style=\"text-align: center;\">\r\n	<span style=\"color:#008000;\"><span style=\"font-size:20px;\">Your nature hideaway, with panoramic vistas of the river or the picturesque Greenland</span></span></p>\r\n<p style=\"text-align: center;\">\r\n	Interior with wooden architecture and furnishings have a warm and natural feel, creating a friendly and inviting ambiance. The balconies with beautiful views of the surrounding scenery,and mesmerizing sunrise enhancing the beauty of River soothe the heart. These accommodations seek to provide a pleasant and memorable experience in the middle of nature, allowing tourists to fully immerse themselves in the beauty of the national park and the tranquility of the river.</p>\r\n', 'Our Rooms', 'our nature hideaway, with panoramic vistas\r\nof the river or the picturesque Greenland', 'Interior with wooden architecture and furnishings have a warm and natural feel, creating a friendly and inviting ambiance.', 1, 3, '2017-04-24 17:25:53', 1),
(3, 'dining-bar', 'Dining & Bar', 'Culinary Excellence in Natural Splendor.', 'a:1:{i:0;s:17:\"zDJrh-dining.webp\";}', '', '', 'a:1:{i:0;s:20:\"iEsdV-restaurant.jpg\";}', '', '<h3 class=\"color-green\">\r\n	Indulge in Epicurean Excellence: Discover Dining at Its Finest</h3>\r\n<p style=\"text-align: center;\">\r\n	We, at River Bank, redefine the culinary landscape, offering an array of exquisite dining experiences that promise to delight your palette and creating amazing memories. The instant you enter our dining venues, you will be enveloped in an environment of elegance and luxury, setting the stage for an amazing gourmet encounter.</p>\r\n', 'Dining & Bar in Chitwan Resort', 'dining in chitwan resort, restaurant in chitwan resort, bar in chitwan resort, luxury resort restaurant chitwan nepal, outdoor dining chitwan resort, cocktail bar chitwan resort, patihani chitwan restaurant resort, best restaurant in chitwan resort,', 'Discover dining experiences at Riverbank Jungle Resort in Chitwan including fine dining restaurants, riverside dining, outdoor meals and premium bar drinks.', 1, 2, '2024-06-14 14:32:24', 0),
(4, 'meeting-events', 'Meeting & Events', 'Every moment and occasion is exceptional', 'a:1:{i:0;s:15:\"6RApu-hall.webp\";}', '', '', 'a:1:{i:0;s:28:\"CsKlR-QPfWs-meetinghall.webp\";}', '', '<h1 style=\"text-align: center;\">\r\n	<span style=\"color:#008000;\"><span style=\"font-size:30px; margin-bottom:32px; display: block; line-height: 1.5;\"><strong>Welcome to Our Exquisite Banquet and Wedding Venue</strong></span></span></h1>\r\n<p style=\"text-align: center;\">\r\n	At Hotel River Bank, we hold the belief that every moment and occasion is exceptional. We&#39;re honored to extend a heartfelt invitation to join us for a celebration beyond compare at our stunning banquet and wedding venue. Set against the breathtaking backdrop of National Park Chitwan, our 5-star oasis awaits to infuse your special day with the perfect blend of opulence, charm, and romance.</p>\r\n', 'Meeting & Event Venues in Chitwan', 'event venue chitwan resort, meeting hall chitwan, conference venue chitwan national park resort, wedding venue chitwan resort, corporate event hall chitwan nepal, banquet hall chitwan resort, event space chitwan resort, conference hall chitwan  ', 'Host meetings, conferences, weddings and corporate events at Riverbank Jungle Resort in Chitwan with elegant halls and beautiful nature surroundings.', 1, 1, '2024-06-14 14:46:01', 0);
INSERT INTO `tbl_package_sub` (`id`, `slug`, `title`, `sub_title`, `detail`, `image`, `header_image`, `image2`, `image3`, `fb_upload`, `feature`, `content`, `facility_title`, `number_room`, `currency`, `discount`, `people_qnty`, `onep_price`, `twop_price`, `threep_price`, `oneb_price`, `twob_price`, `threeb_price`, `extra_bed`, `meta_title`, `meta_keywords`, `meta_description`, `status`, `sortorder`, `added_date`, `type`) VALUES
(1, 'villa-with-private-plunge-pool', 'Villa with Private Plunge Pool', '', 'Our Private Villa beckons with exclusivity. Imagine unwinding in your own oasis – a tranquil retreat ', 'a:6:{i:0;s:23:\"3UY28-MbYxc-villa1.webp\";i:1;s:23:\"9E6PF-fRfDZ-villa3.webp\";i:2;s:23:\"mMwK7-W3i4q-villa1.webp\";i:3;s:23:\"gOiXL-GdLsd-villa2.webp\";i:4;s:20:\"nLkbe-P3iN5-dv1.webp\";i:5;s:20:\"DyeCS-ySNVn-dv4.webp\";}', 'RxDul-DkCaQ-delxevilla.webp', 'RGYJ8-villabanner.webp', '', 0x584f3269342d47644c73642d76696c6c61322e6a7067, , '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;Secluded Paradise&quot;</strong></span></span></p>\r\n<p>\r\n	Our Private Villa beckons with exclusivity. Imagine unwinding in your own oasis &ndash; a tranquil retreat where lush greenery surrounds your private plunge pool. Whether you&rsquo;re sipping cocktails by the water&rsquo;s edge or stargazing from your terrace, this villa promises an intimate escape.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', '', 14, '', 0, 1, 0, 0, 0, 0, 0, 0, '', 'Private Jungle Villa Resort Chitwan | Luxury Safari Stay', 'jungle villa resort chitwan, jungle safari resort chitwan, private villa chitwan, luxury jungle resort chitwan, private pool villa chitwan, chitwan jungle stay', 'Escape to an exclusive private jungle villa resort in Chitwan with lush greenery, a plunge pool, and easy access to jungle safari experiences.', 1, 3, '2017-04-24 17:34:20', 1),
(2, 'super-deluxe-room', 'Super Deluxe Room', '', 'Our Super Deluxe Room offers an exclusive escape with a private balcony overlooking the vast Terai Grassland. ', 'a:5:{i:0;s:20:\"zE6Cx-VPITe-sd2.webp\";i:1;s:20:\"1pKc4-hRpSu-sd3.webp\";i:2;s:20:\"ivKXK-tDKXU-sd4.webp\";i:3;s:20:\"Jkzc3-PrBmO-sd1.webp\";i:4;s:20:\"FPlwh-agwWt-sd5.webp\";}', 'yLYe7-NY5U6-sdbanner.webp', 'GA4k2-superdeluxetwin.webp', '', 0x47754a64642d68527053752d7364332e6a7067, , '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;Riverfront Bliss&quot;</strong></span></span></p>\r\n<p>\r\n	Our Super Deluxe Room offers an exclusive escape with a private balcony overlooking the vast Terai Grassland. Imagine sipping your morning coffee while the river gently meanders below. Whether you&rsquo;re a nature enthusiast or seeking tranquility, this room promises an unforgettable stay.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', '', 17, '', 0, 1, 0, 0, 0, 0, 0, 0, '', 'Riverfront Super Deluxe Room | Nature & Comfort', 'super deluxe riverfront room, riverfront hotel room, super deluxe room with balcony, terai grassland view room, nature view hotel room, tranquil river stay', 'Enjoy a Super Deluxe Riverfront Room with a private balcony overlooking the Terai grassland and flowing river—perfect for nature lovers and peaceful escapes.', 1, 4, '2017-04-27 13:33:02', 1),
(3, 'deluxe-room', 'Deluxe Room', '', 'Imagine waking up to breathtaking mountain vistas – a symphony of mist-kissed peaks and serene valleys.', 'a:4:{i:0;s:22:\"vXyLM-mvGcb-room1.webp\";i:1;s:22:\"l9N2u-t1gsy-room2.webp\";i:2;s:20:\"svFYF-nltpL-dv2.webp\";i:3;s:20:\"BVXP3-6VS0l-dv3.webp\";}', 'YMS9E-jAuSs-deluxebanner.webp', 'DNM2k-deluxerooms.webp', '', 0x6e3969504d2d6a417553732d64656c75786562616e6e65722e6a7067, , '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;Mountain Magic&quot;</strong></span></span></p>\r\n<p>\r\n	Imagine waking up to breathtaking mountain vistas &ndash; a symphony of mist-kissed peaks and serene valleys. Our deluxe rooms offer this enchanting experience, where every morning feels like a canvas painted by nature itself. Whether you&rsquo;re an adventurer seeking solace or a romantic soul, our mountain retreat awaits.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', '', 34, '', 0, 1, 0, 0, 0, 0, 0, 0, '', 'Deluxe Room | Scenic Retreat', 'deluxe mountain view room, mountain view hotel room, deluxe room with mountain view, scenic mountain stay, romantic mountain retreat, nature view room, deluxe room', 'Wake up to breathtaking mountain views in our Deluxe Room, offering comfort, serenity, and a perfect retreat for adventurers and romantic getaways.', 1, 5, '2017-04-27 13:34:44', 1),
(5, 'presidential-suite', 'Presidential Suite', '', 'Our Presidential Suite redefines opulence. Imagine stepping onto your private terrace, where the plunge pool overlooks the horizon.', 'a:4:{i:0;s:13:\"gdBre-dv1.jpg\";i:1;s:13:\"VCE9f-dv3.jpg\";i:2;s:13:\"DD943-dv2.jpg\";i:3;s:13:\"Di43f-dv4.jpg\";}', 'nxan7-roombanner.jpg', 'Y48Af-superdeluxe.jpg', '', '', , '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;Unsurpassed Hospitality&quot;</strong></span></span></p>\r\n<p>\r\n	Unrivaled Luxury: Our Presidential Suite redefines opulence. Imagine stepping onto your private terrace, where the plunge pool overlooks the horizon. With spacious interiors, bespoke furnishings, and personalized service, this suite is where grandeur meets serenity.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', '', 0, '', 0, 1, 0, 0, 0, 0, 0, 0, '', 'Presidential Suite', 'Presidential Suite', 'Presidential Suite', 0, 1, '2017-04-27 13:39:26', 1),
(6, 'executive-suite', 'Executive Suite', '', 'Indulge in unparalleled luxury in our Executive Suite with Plunge Pool, where sophistication meets nature. \r\n', 'a:4:{i:0;s:13:\"fOHj8-dv1.jpg\";i:1;s:13:\"hVbhA-dv3.jpg\";i:2;s:13:\"BvKOP-dv4.jpg\";i:3;s:13:\"BDsrE-dv2.jpg\";}', 'NSPLo-roombanner.jpg', 'NVlFj-deluxeroom.jpg', '', '', , '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;canvas of nature&quot;</strong></span></span></p>\r\n<p>\r\n	Indulge in unparalleled luxury in our Executive Suite with Plunge Pool, where sophistication meets nature. Revel in the elegance of spacious interiors, unwind in your private plunge pool, and soak in breathtaking jungle views. Perfect for those seeking exclusivity and tranquility, this suite promises an extraordinary escape.</p>\r\n<p>\r\n	&nbsp;</p>\r\n', '', 4, '', 0, 1, 0, 0, 0, 0, 0, 0, '', 'Executive Suite', 'Executive Suite', 'Executive Suite', 0, 2, '2017-04-27 13:40:22', 1),
(7, 'the-signature-restaurant', 'The Signature Restaurant', '', 'Experience culinary mastery at our flagship restaurant, where our chefs conjure up gastronomic marvels. Dive into a realm of flavors, where premium ingredients are transformed into aesthetically pleasing and palatable masterpieces. Ideal for a romantic dinner or a celebratory occasion, our Signature Restaurant is synonymous with an unparalleled dining adventure.', 'a:4:{i:0;s:21:\"1G9Sk-APqSf-res1.webp\";i:1;s:21:\"A69ix-A5FWZ-res3.webp\";i:2;s:21:\"Y0GOF-XmQMW-res2.webp\";i:3;s:21:\"MaEgc-6HOtd-res4.webp\";}', 'oUDo9-qF21J-resbanner.webp', 'lsxRy-tpGmt-3.webp', '', 0x7953506b722d413546575a2d726573332e6a7067, 0x613a303a7b7d, '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;Gastronomic Elegance at River Bank &quot;</strong></span></span></p>\r\n<p>\r\n	Indulge in culinary excellence at The Signature Restaurant. Nestled within our luxurious resort, this gastronomic haven offers a symphony of flavors, artfully crafted dishes, and impeccable service. From candlelit dinners to panoramic views, every moment here is a celebration of fine dining.</p>\r\n<div class=\"restaurant_table\">\r\n	<h3>\r\n		Opening Time and Occupancy</h3>\r\n	<table class=\"table table-bordered\">\r\n		<thead>\r\n			<tr>\r\n				<th>\r\n					Occupancy</th>\r\n				<th>\r\n					Type</th>\r\n				<th>\r\n					Opening Time</th>\r\n				<th>\r\n					Cuisine serve</th>\r\n			</tr>\r\n		</thead>\r\n		<tbody>\r\n			<tr>\r\n				<td>\r\n					100 pax</td>\r\n				<td>\r\n					&nbsp;All day dining&nbsp;</td>\r\n				<td>\r\n					07:00 AM - 10:00 PM</td>\r\n				<td>\r\n					<div>\r\n						&nbsp;Multicuisine</div>\r\n				</td>\r\n			</tr>\r\n		</tbody>\r\n	</table>\r\n</div>\r\n<p>\r\n	&nbsp;</p>\r\n', '', 0, '', 0, 0, 0, 0, 0, 0, 0, 0, '', 'The Signature Restaurant', 'signature restaurant chitwan resort, fine dining restaurant chitwan nepal, luxury restaurant chitwan national park resort, nepali cuisine chitwan resort, international cuisine chitwan resort restaurant, resort dining, best restaurant in chitwan', 'Enjoy fine dining at The Signature Restaurant at Riverbank Jungle Resort in Chitwan serving Nepali, Indian and international cuisine.', 1, 10, '2024-06-14 14:33:08', 3),
(8, 'al-fresco-dining', 'Al Fresco Dining', '', 'Our open-air dining beckons you with refreshing breezes and mesmerizing vistas of the Ratpi River and verdant forests. Choose to dine under the starlit sky or soak in the daytime radiance, our al fresco settings offer a charming escape into nature. Savor the freshest flavors, sourced locally and cultivated regionally, for a true taste of the locale.', 'a:3:{i:0;s:20:\"et3vZ-ISNrq-al3.webp\";i:1;s:20:\"1uFWS-CuJfQ-al1.webp\";i:2;s:20:\"h3wMb-mym3B-al2.webp\";}', 'hVyVo-6h5Vx-albanner.webp', '3Rjee-QvSln-albanner.webp', '', '', 0x613a303a7b7d, '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;A Breath of Fresh Air &quot;</strong></span></span></p>\r\n<p>\r\n	Our open-air dining beckons you with refreshing breezes and mesmerizing vistas of the Ratpi River and verdant forests. Choose to dine under the starlit sky or soak in the daytime radiance, our al fresco settings offer a charming escape into nature. Savor the freshest flavors, sourced locally and cultivated regionally, for a true taste of the locale.</p>\r\n', '', 0, '', 0, 0, 0, 0, 0, 0, 0, 0, '', 'Al Fresco Dining in Chitwan', 'al fresco dining chitwan resort, outdoor dining chitwan national park resort, open air restaurant chitwan nepal, jungle resort outdoor dining nepal,outdoor restaurant, nature dining experience chitwan, romantic outdoor dining chitwan resort', 'Experience al fresco dining at Riverbank Jungle Resort in Chitwan with delicious cuisine, fresh air and beautiful jungle surroundings.', 1, 9, '2024-06-14 14:33:54', 3),
(9, 'riverside-retreat', 'Riverside Retreat', '', 'Dine amidst the natural splendor, where the soft river zephyrs and the majestic National Park provide a tranquil and enchanting backdrop. Indulge in a meal that not only pleases the palate but also enriches the soul with lasting memories. The riverside transforms into a magical dining haven as dusk falls, adding a touch of enchantment to your evening.', 'a:2:{i:0;s:27:\"dJLZJ-VTZvA-riverside1.webp\";i:1;s:27:\"Npb4i-cVMVV-riverside2.webp\";}', 'THpNL-S5iRB-riversidebanner.webp', 'mcqRp-du1lv-riverside.webp', '', 0x6a315466592d56545a76412d726976657273696465312e6a7067, 0x613a303a7b7d, '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;A Soulful Retreat &quot;</strong></span></span></p>\r\n<p>\r\n	Dine amidst the natural splendor, where the soft river zephyrs and the majestic National Park provide a tranquil and enchanting backdrop. Indulge in a meal that not only pleases the palate but also enriches the soul with lasting memories. The riverside transforms into a magical dining haven as dusk falls, adding a touch of enchantment to your evening.</p>\r\n', '', 0, '', 0, 0, 0, 0, 0, 0, 0, 0, '', 'Riverside Retreat Dining', 'riverside dining chitwan resort, riverside retreat dining chitwan, riverbank jungle resort dining experience, outdoor dining chitwan resort, nature dining chitwan nepal, romantic riverside restaurant chitwan, patihani chitwan resort dining', 'Enjoy peaceful riverside dining at Riverbank Jungle Resort in Chitwan with beautiful river views, fresh cuisine and a relaxing jungle resort atmosphere.', 1, 8, '2024-06-14 14:38:01', 3),
(10, 'the-classic-bar', 'The Classic Bar', '', 'Step into The Classic Bar, where the legacy of cocktail culture is celebrated with modern flair. This elegant sanctuary within our resort is more than just a bar—it\'s a journey through time. Adorned with polished wood and sumptuous furnishings, our bar is a nod to the golden age of mixology. Our adept mixologists blend timeless recipes with inventive techniques, presenting a selection of classic and custom cocktails.', 'a:4:{i:0;s:21:\"5dscG-nrVl1-bar2.webp\";i:1;s:21:\"CzpXI-9FblM-bar1.webp\";i:2;s:20:\"3pqAv-StcFu-bar.webp\";i:3;s:21:\"5h6Ko-8A2LA-bar3.webp\";}', 'nbC7b-e3CvD-barbanner.webp', 'nYFDG-QArb7-2.webp', '', 0x395962346f2d53746346752d6261722e6a7067, 0x613a303a7b7d, '<p>\r\n	<span style=\"color:#006699;\"><span style=\"font-size:20px;\"><strong>&ldquo;Where Time-Honored Charm Meets Contemporary Craft &quot;</strong></span></span></p>\r\n<p>\r\n	Step into The Classic Bar, where the legacy of cocktail culture is celebrated with modern flair. This elegant sanctuary within our resort is more than just a bar&mdash;it&#39;s a journey through time. Adorned with polished wood and sumptuous furnishings, our bar is a nod to the golden age of mixology. Our adept mixologists blend timeless recipes with inventive techniques, presenting a selection of classic and custom cocktails.</p>\r\n', '', 0, '', 0, 0, 0, 0, 0, 0, 0, 0, '', 'The Classic Bar', 'classic bar chitwan resort, cocktail bar chitwan, resort bar chitwan national park, jungle resort cocktail bar nepal, drinks lounge chitwan resort, premium cocktails chitwan resort, night bar chitwan resort, best resort bar chitwan nepal, chitwan bar', 'Relax at The Classic Bar at Riverbank Jungle Resort in Chitwan. Enjoy premium cocktails, wines and refreshing drinks in a stylish jungle resort lounge.', 1, 7, '2024-06-14 14:38:30', 3),
(11, 'serenity-hall', 'Serenity Hall ', '', 'A sophisticated oasis for meetings and corporate events. With its sleek design, cutting-edge technology, and serene ambiance, this venue inspires productivity and creativity. Elevate your business gatherings in the lap of luxury.', 'a:3:{i:0;s:15:\"xAAmh-hall1.jpg\";i:1;s:15:\"FBhT9-hall3.jpg\";i:2;s:15:\"Vvmzp-hall2.jpg\";}', 'hV9bS-meetinghall.jpg', 'dQiXo-serenity.jpg', '', 0x64643671582d56766d7a702d68616c6c322e6a7067, , '<h3 class=\"color-green\">\r\n	Tailored to fit your program perfectly</h3>\r\n<p>\r\n	A sophisticated oasis for meetings and corporate events. With its sleek design, cutting-edge technology, and serene ambiance, this venue inspires productivity and creativity. Elevate your business gatherings in the lap of luxury.</p>\r\n<div class=\"event_halls\">\r\n	<table class=\"table table-bordered\">\r\n		<thead>\r\n			<tr>\r\n				<th>\r\n					Hall Size</th>\r\n				<th>\r\n					U Setup</th>\r\n				<th>\r\n					Classroom Setup</th>\r\n				<th>\r\n					Theater Setup</th>\r\n				<th>\r\n					Round Table Setup</th>\r\n			</tr>\r\n		</thead>\r\n		<tbody>\r\n			<tr>\r\n				<td>\r\n					1640 sq.ft</td>\r\n				<td>\r\n					60 cover</td>\r\n				<td>\r\n					50 cover</td>\r\n				<td>\r\n					200 cover</td>\r\n				<td>\r\n					100 cover</td>\r\n			</tr>\r\n		</tbody>\r\n	</table>\r\n</div>\r\n', '', 0, '', 0, 0, 0, 0, 0, 0, 0, 0, '', 'Serenity Hall Event Venue', 'serenity hall chitwan event venue, meeting hall chitwan resort, wedding venue chitwan resort nepal, corporate meeting venue chitwan, conference hall chitwan national park resort, event space chitwan resort, resort event venue', 'Serenity Hall at Riverbank Jungle Resort is an elegant venue for conferences, weddings and corporate meetings surrounded by nature in Chitwan.', 1, 9, '2024-06-14 14:47:13', 4),
(12, 'regal-ball-room', 'Regal Ball Room', '', 'Where elegance dances with grandeur. This opulent venue, adorned with crystal chandeliers and silk drapes, sets the stage for unforgettable events. From weddings to galas, every moment in the Regal Ballroom is a symphony of sophistication.\r\n', 'a:4:{i:0;s:22:\"N75r6-VuXVA-hall4.webp\";i:1;s:22:\"LJMNm-zmgZ5-hall6.webp\";i:2;s:22:\"RMrLD-3YlMD-hall5.webp\";i:3;s:22:\"WIeIO-OJ58l-hall7.webp\";}', 'GE4Sl-YoClY-hall.webp', '7XIGW-pQINB-hall.webp', '', 0x47473043382d7a6d675a352d68616c6c362e6a7067, , '<h3 class=\"color-green\">\r\n	Your premium event planning partner</h3>\r\n<p>\r\n	Where elegance dances with grandeur. This opulent venue, adorned with crystal chandeliers and silk drapes, sets the stage for unforgettable events. From weddings to galas, every moment in the Regal Ballroom is a symphony of sophistication.</p>\r\n<div class=\"event_halls\">\r\n	<table class=\"table table-bordered\">\r\n		<thead>\r\n			<tr>\r\n				<th>\r\n					Hall Size</th>\r\n				<th>\r\n					U Setup</th>\r\n				<th>\r\n					Classroom Setup</th>\r\n				<th>\r\n					Theater Setup</th>\r\n				<th>\r\n					Round Table Setup</th>\r\n			</tr>\r\n		</thead>\r\n		<tbody>\r\n			<tr>\r\n				<td>\r\n					1575 sq.ft</td>\r\n				<td>\r\n					40-50 cover</td>\r\n				<td>\r\n					30-40 cover</td>\r\n				<td>\r\n					160-170 cover</td>\r\n				<td>\r\n					70-80 cover</td>\r\n			</tr>\r\n		</tbody>\r\n	</table>\r\n</div>\r\n', '', 0, '', 0, 0, 0, 0, 0, 0, 0, 0, '', 'Regal Ballroom Event Venue', 'regal ballroom chitwan resort venue, luxury wedding venue chitwan nepal, ballroom event venue chitwan resort, corporate event hall chitwan, conference venue chitwan national park resort, wedding ballroom chitwan resort, resort events venue', 'Host grand weddings and events at Regal Ballroom at Riverbank Jungle Resort in Chitwan with elegant space and luxury hospitality.', 1, 10, '2024-06-14 14:47:44', 4);
