INSERT INTO `tbl_slideshow` (`id`, `title`, `image`, `linksrc`, `linktype`, `content`, `status`, `m_status`, `added_date`, `sortorder`, `type`) VALUES
(1, 'Reception', '130J5-slider4.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Elegant Indoor Retreat in Chitwan</h3>\r\n<h2>\r\n	A peaceful riverside jungle escape near Chitwan National Park, blending wildlife, comfort, and nature</h2>\r\n', 1, 0, '2017-04-23 16:47:35', 8, 1),
(11, 'Drone night view', '8OSOw-riverbank.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Aerial Night Overview</h3>\r\n<h2>\r\n	Our beautiful resort surrounded by nature near the Rapti River and Chitwan National Park</h2>\r\n', 1, 0, '2024-07-10 16:12:13', 0, 1),
(9, 'Foods', '1FdlN-food.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Elegant Dining Variety at the Resort</h3>\r\n<h2>\r\n	Enjoy Nepali, Indian, Japanese, and Continental cuisine by the Rapti River</h2>\r\n', 1, 0, '2024-07-05 12:44:10', 4, 1),
(3, 'Room', 'lBdby-slider6.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Serene Jungle Comfort in Chitwan</h3>\r\n<h2>\r\n	Tranquil riverside living by Chitwan National Park</h2>\r\n', 1, 0, '2017-04-23 16:48:48', 7, 1),
(4, 'Pool', 'BPurv-slider3.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Refreshing Pool Experience</h3>\r\n<h2>\r\n	Relax by our outdoor pool with peaceful Rapti River views near Chitwan National Park</h2>\r\n', 1, 0, '2017-04-27 12:41:04', 3, 1),
(5, 'Evening View', 'UNCbd-slider2.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Twilight Serenity at the Resort</h3>\r\n<h2>\r\n	Enjoy calm evenings with glowing views of our resort by the Rapti River near Chitwan National Park</h2>\r\n', 1, 0, '2017-04-27 12:47:48', 2, 1),
(6, 'Night View', 'jVSxk-slider1.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Evening Pool Serenity in Chitwan</h3>\r\n<h2>\r\n	Relax in our beautifully lit resort and pool by the Rapti River near Chitwan National Park</h2>\r\n', 1, 0, '2017-05-04 16:58:15', 1, 1),
(7, 'Dining', 'yKT7u-slider5.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Fine Dining in the Restaurant</h3>\r\n<h2>\r\n	Fresh meals with beautiful Rapti River views near Chitwan National Park</h2>\r\n', 1, 0, '2017-05-04 17:00:15', 6, 1),
(12, 'Riverside Retreat', 'wZNZr-riverside.webp', '', 0, '<h4>\r\n	Welcome to River Bank Jungle Resort</h4>\r\n<h3 style=\"font-size: 54px;\">\r\n	Serene Breakfast Riverside Setting</h3>\r\n<h2>\r\n	Peaceful stay by the Rapti River near Chitwan National Park</h2>\r\n', 1, 0, '2024-07-10 16:20:46', 5, 1);
